## pages/Locations.tsx

Updated the text to highlight the flagship store and updated the list handling to display branch ratings.

<change>
<file>pages/Locations.tsx</file>
<description>Update UI to distinguish Flagship store and show ratings/notes for other branches</description>
<content><![CDATA[
import React, { useState } from 'react';
import { BRANCHES } from '../constants';
import { MapPin, Phone, Clock, Navigation, Star, Info } from 'lucide-react';

const Locations: React.FC = () => {
  const [activeBranchId, setActiveBranchId] = useState(BRANCHES[0].id);
  const activeBranch = BRANCHES.find(b => b.id === activeBranchId) || BRANCHES[0];

  return (
    <div className="pt-24 pb-20 bg-white min-h-screen">
      <div className="container mx-auto px-4">

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">

          {/* List of Branches */}
          <div className="lg:col-span-1 space-y-6">
            <div>
              <span className="text-brand-pink font-bold tracking-wider uppercase text-xs">Since 1995</span>
              <h1 className="font-display text-4xl font-bold text-brand-dark mb-2">Our Locations</h1>
              <p className="text-gray-500">
                Visit our <span className="font-bold text-brand-pink">Original Flagship in West Mambalam</span>. 
                We also have branches serving smiles across Chennai.
              </p>
            </div>

            <div className="space-y-4">
              {BRANCHES.map((branch) => (
                <button
                  key={branch.id}
                  onClick={() => setActiveBranchId(branch.id)}
                  className={`w-full text-left p-5 rounded-2xl transition-all border-2 group relative overflow-hidden ${
                    activeBranchId === branch.id 
                      ? 'border-brand-pink bg-brand-pink/5 shadow-md' 
                      : 'border-gray-100 bg-white hover:border-brand-pink/30'
                  }`}
                >
                  <div className="flex justify-between items-start mb-2 relative z-10">
                    <h3 className={`font-bold text-lg ${activeBranchId === branch.id ? 'text-brand-dark' : 'text-gray-800'}`}>
                      {branch.name}
                    </h3>
                    {branch.isPrimary && (
                      <span className="bg-brand-yellow text-brand-dark text-[10px] font-bold px-2 py-1 rounded shadow-sm">HQ</span>
                    )}
                  </div>

                  <p className="text-sm text-gray-500 mb-3 leading-relaxed relative z-10 line-clamp-2">
                    {branch.address}
                  </p>

                  <div className="flex flex-wrap items-center gap-3 text-xs font-medium relative z-10">
                    <div className="flex items-center gap-1 text-gray-700 bg-gray-100 px-2 py-1 rounded-full">
                      <Phone size={12} /> {branch.phone}
                    </div>
                    {branch.rating && (
                      <div className="flex items-center gap-1 text-orange-600 bg-orange-50 px-2 py-1 rounded-full">
                        <Star size={12} fill="currentColor" /> {branch.rating}
                      </div>
                    )}
                  </div>

                  {branch.notes && (
                     <div className="mt-2 text-xs text-brand-pink italic flex items-center gap-1">
                       <Info size={12} /> {branch.notes}
                     </div>
                  )}
                </button>
              ))}
            </div>

            <div className="bg-brand-teal/10 p-6 rounded-2xl border border-brand-teal/20">
              <h4 className="font-bold flex items-center gap-2 mb-2 text-brand-dark">
                <Clock size={18} /> Operating Hours
              </h4>
              <ul className="space-y-2 text-sm text-gray-600">
                <li className="flex justify-between">
                  <span>West Mambalam</span>
                  <span className="font-bold">10:00 AM - 10:30 PM</span>
                </li>
                <li className="flex justify-between">
                  <span>Other Branches</span>
                  <span className="font-bold">10:00 AM - 10:00 PM</span>
                </li>
              </ul>
              <p className="text-xs mt-4 text-gray-500 italic">Hours subject to change. Call to confirm.</p>
            </div>
          </div>

          {/* Map Display */}
          <div className="lg:col-span-2 min-h-[500px] h-auto lg:h-[600px] bg-gray-100 rounded-3xl overflow-hidden shadow-inner relative flex flex-col">
            {activeBranch.mapUrl ? (
              <iframe 
                src={activeBranch.mapUrl} 
                className="w-full h-full flex-grow"
                style={{ border: 0 }} 
                allowFullScreen={true} 
                loading="lazy" 
                referrerPolicy="no-referrer-when-downgrade"
                title={`${activeBranch.name} Map`}
              ></iframe>
            ) : (
              <div className="flex-grow flex flex-col items-center justify-center text-gray-400 bg-gray-50 p-8 text-center">
                <div className="bg-white p-6 rounded-full shadow-sm mb-4">
                   <MapPin size={48} className="text-gray-300"/>
                </div>
                <h3 className="text-lg font-bold text-gray-600 mb-2">Map View Not Available</h3>
                <p className="max-w-xs text-sm">
                  We haven't added the map pin for <strong>{activeBranch.name}</strong> yet. 
                  Please use the button below to search on Google Maps directly.
                </p>
              </div>
            )}

            <div className="absolute bottom-6 left-6 right-6 bg-white p-5 rounded-2xl shadow-xl border border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4 animate-in slide-in-from-bottom-4 duration-500">
              <div className="text-center sm:text-left">
                <p className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1">Selected Location</p>
                <p className="font-bold text-xl text-brand-dark">{activeBranch.name}</p>
                <p className="text-sm text-gray-500 truncate max-w-xs">{activeBranch.address}</p>
              </div>
              <a 
                href={`https://maps.google.com/?q=${encodeURIComponent(activeBranch.address + " Vinu's Igloo")}`}
                target="_blank"
                rel="noreferrer"
                className="bg-brand-pink text-white px-6 py-3 rounded-xl font-bold text-sm hover:bg-brand-dark transition-colors flex items-center gap-2 shadow-lg shadow-brand-pink/20 whitespace-nowrap"
              >
                <Navigation size={18} />
                Get Directions
              </a>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default Locations;
]]></content>
</change>

